"""Core data processing engine."""
import logging
from typing import Any, Callable, Optional

logger = logging.getLogger(__name__)


class DataProcessor:
    """Main processing engine that runs data through a pipeline of stages."""

    def __init__(self, name: str, max_retries: int = 3):
        self.name = name
        self.max_retries = max_retries
        self._stages: list[Callable] = []
        self._error_count = 0
        self._processed_count = 0
        logger.info("DataProcessor '%s' initialized", name)

    def add_stage(self, stage_fn: Callable) -> "DataProcessor":
        """Add a processing stage to the pipeline. Returns self for chaining."""
        self._stages.append(stage_fn)
        return self

    def process(self, data: Any) -> Optional[Any]:
        """Run data through all pipeline stages sequentially."""
        result = data
        for i, stage in enumerate(self._stages):
            attempt = 0
            while attempt < self.max_retries:
                try:
                    result = stage(result)
                    break
                except Exception as exc:
                    attempt += 1
                    self._error_count += 1
                    logger.warning(
                        "Stage %d failed (attempt %d/%d): %s",
                        i, attempt, self.max_retries, exc,
                    )
                    if attempt >= self.max_retries:
                        logger.error("Stage %d exhausted retries, aborting", i)
                        return None
        self._processed_count += 1
        return result

    def process_batch(self, items: list[Any]) -> list[Any]:
        """Process a batch of items, filtering out failures."""
        results = []
        for item in items:
            data_processor_result = self.process(item)
            if data_processor_result is not None:
                results.append(data_processor_result)
        return results

    @property
    def stats(self) -> dict:
        """Return processing statistics."""
        return {
            "name": self.name,
            "stages": len(self._stages),
            "processed": self._processed_count,
            "errors": self._error_count,
        }

    def __repr__(self) -> str:
        return f"DataProcessor(name={self.name!r}, stages={len(self._stages)})"

