"""Configuration management for dataflow pipelines."""
from typing import Any

# Default processor class name used for dynamic instantiation
PROCESSOR_TYPE = "DataProcessor"

# Default configuration values
DEFAULTS = {
    "max_retries": 3,
    "batch_size": 100,
    "timeout_seconds": 30,
    "log_level": "INFO",
}


class ProcessorConfig:
    """Holds configuration for a data processing pipeline."""

    def __init__(self, **kwargs: Any):
        self._config = {**DEFAULTS, **kwargs}
        self._config["processor_class"] = kwargs.get(
            "processor_class", "DataProcessor"
        )

    def get(self, key: str, default: Any = None) -> Any:
        """Get a configuration value."""
        return self._config.get(key, default)

    def set(self, key: str, value: Any) -> None:
        """Set a configuration value."""
        self._config[key] = value

    @property
    def processor_class_name(self) -> str:
        """Return the configured processor class name."""
        return self._config["processor_class"]

    @property
    def is_default_processor(self) -> bool:
        """Check if using the default processor class."""
        return self._config["processor_class"] == PROCESSOR_TYPE

    def to_dict(self) -> dict:
        """Export config as dictionary."""
        return dict(self._config)

    def __repr__(self) -> str:
        return f"ProcessorConfig({self._config!r})"

