"""Handler registry — maps class names to handler instances."""
from typing import Any, Callable, Optional
from .processor import DataProcessor

# Registry mapping class names to their constructors
_REGISTRY: dict[str, type] = {}

# Built-in handlers that ship with the framework
BUILTIN_HANDLERS = {
    "DataProcessor": DataProcessor,
}


def register_handler(name: str, cls: type) -> None:
    """Register a handler class by name."""
    if name in _REGISTRY:
        raise ValueError(f"Handler '{name}' already registered")
    _REGISTRY[name] = cls


def get_handler(name: str) -> Optional[type]:
    """Look up a handler class by name, checking custom then built-in."""
    if name in _REGISTRY:
        return _REGISTRY[name]
    return BUILTIN_HANDLERS.get(name)


def list_handlers() -> list[str]:
    """List all available handler names."""
    all_names = set(BUILTIN_HANDLERS.keys()) | set(_REGISTRY.keys())
    return sorted(all_names)


def create_instance(name: str, **kwargs: Any) -> Any:
    """Create an instance of a registered handler."""
    cls = get_handler(name)
    if cls is None:
        raise KeyError(f"No handler registered for '{name}'")
    return cls(**kwargs)

