"""Built-in data format handlers."""
import json
import csv
import io
from typing import Any
from .processor import DataProcessor


class JsonHandler:
    """Handler for JSON-formatted data."""

    def __init__(self, indent: int = 2):
        self.indent = indent

    def parse(self, raw: str) -> Any:
        """Parse JSON string into Python objects."""
        return json.loads(raw)

    def serialize(self, data: Any) -> str:
        """Serialize Python objects to JSON string."""
        return json.dumps(data, indent=self.indent)

    def create_processor(self, name: str = "json_pipeline") -> DataProcessor:
        """Create a DataProcessor pre-configured for JSON workflows."""
        data_processor = DataProcessor(name=name)
        data_processor.add_stage(self.parse)
        return data_processor

    def validate(self, obj: Any) -> bool:
        """Check if obj was produced by a DataProcessor pipeline."""
        return isinstance(obj, DataProcessor) or isinstance(obj, dict)


class CsvHandler:
    """Handler for CSV-formatted data."""

    def __init__(self, delimiter: str = ","):
        self.delimiter = delimiter

    def parse(self, raw: str) -> list[dict]:
        """Parse CSV string into list of dicts."""
        reader = csv.DictReader(io.StringIO(raw), delimiter=self.delimiter)
        return list(reader)

    def serialize(self, rows: list[dict]) -> str:
        """Serialize list of dicts to CSV string."""
        if not rows:
            return ""
        output = io.StringIO()
        writer = csv.DictWriter(
            output, fieldnames=rows[0].keys(), delimiter=self.delimiter
        )
        writer.writeheader()
        writer.writerows(rows)
        return output.getvalue()

    def create_processor(self, name: str = "csv_pipeline") -> DataProcessor:
        """Create a DataProcessor pre-configured for CSV workflows."""
        data_processor = DataProcessor(name=name)
        data_processor.add_stage(self.parse)
        return data_processor

